command.text:
if exists(select * from @@table where stt_rec_nv = @stt_rec_nv and nam = @nam and ky = @ky) begin select 'ma_nv' as field, @$exists as message return end declare @@master varchar(128) select @datetime0 = getdate(), @datetime2 = getdate(), @user_id0 = @@userID, @user_id2 = @@userID, @@master = '@@table'
&CommandGetIdentityNumber;
update @dct set stt_rec = @stt_rec

script.text:

function active$hrAMCriteria(f) {
  f.add_onResponseComplete(on$hrAMCriteria$ResponseComplete);
  set$DefaultValue(f);
}
function scatter$hrAMCriteria(f) {set$DefaultValue(f);}
function close$hrAMCriteria(f) {try {f.remove_onResponseComplete(on$hrAMCriteria$ResponseComplete)} catch (ex) {}}
function set$DefaultValue(f) {
  if (f._action != 'View') {
    var c = (f._language == 'v' ? '' : '2');
    f.setReadOnlyFields('ten_bp' + c + ', ten_vtr' + c);
  }
  if (f._action == 'New') {
    var v = new Date();
    f.setItemValues('ky, nam', [v.getMonth() + 1, v.getFullYear()]);
  }
}
function on$hrAMCriteria$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      break;
    case 'Employee':
      f.setItemControlBehavior('stt_rec_nv', result[0].Value, true);
      f.setItemControlBehavior('ten_bp%l', result[1].Value, true);
      f.setItemControlBehavior('ten_vtr%l', result[2].Value, true);
      break;
    default:
      break;
  }
}
function onchange$hrAMCriteria$Employee(o) {o.parentForm.request('Employee', 'Employee', ['ma_nv']);}
function when$hrAMCriteriaCopying(f) {f.setItemValue('stt_rec', '');}
